{
  "mitigation_currently_implemented": "Configure firewall rules on the UbuntuComputer to restrict file access and disable reading sensitive file types like .png, .yml, and .wav by non-system processes",
  "comments": "Configured iptables firewall rules on the UbuntuComputer to drop outgoing traffic on port 8443 containing sensitive file extensions .png, .yml, and .wav. This mitigation aims to prevent exfiltration of these sensitive file types over the attacker's command and control channel while the attacker remains active on the host.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".png\" --algo kmp -j DROP",
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".yml\" --algo kmp -j DROP",
    "iptables -A OUTPUT -p tcp --dport 8443 -m string --string \".wav\" --algo kmp -j DROP"
  ]
}
